    var act_code = snap && snap.active ? snap.active.contract : '';
    var sw_code = snap && snap.swing ? snap.swing.contract : '';
    var dca_code = snap && snap.dca ? snap.dca.contract : '';
    var swLogicStr = (fund.swing_logic || '').toLowerCase();
    var isSwingShort = swLogicStr.includes('ưu tiên canh bán') || swLogicStr.includes('swing short');
    var swStrat = isSwingShort ? '📉 LỆNH: SHORT' : '📈 LỆNH: LONG';
    var swEntry = isSwingShort ? fund.swing_short_entry : fund.swing_long_entry;
    var swSl = isSwingShort ? fund.swing_short_sl : fund.swing_long_sl;
    var swTp = isSwingShort ? fund.swing_short_tp : fund.swing_long_tp;
    
    var dcaLogicStr = (fund.seasonal_strategy || '').toLowerCase();
