    if (fund.us_planting) usdaHTML += `<div class="sr" style="align-items:flex-start;"><span class="sl">Gieo trồng US</span><span class="sv">${renderSv(fund.us_planting, 'latest')}</span></div>`;
    if (fund.harvest_progress) usdaHTML += `<div class="sr" style="align-items:flex-start;"><span class="sl">Thu hoạch US</span><span class="sv">${renderSv(fund.harvest_progress, 'latest')}</span></div>`;
    if (fund.crop_condition) usdaHTML += `<div class="sr" style="align-items:flex-start;"><span class="sl">Chất lượng G/E</span><span class="sv">${renderSv(fund.crop_condition, 'latest')}</span></div>`;
